DROP TABLE IF EXISTS `aowow_seo_descriptions`;
CREATE TABLE `aowow_seo_descriptions` (
  `page` varchar(255) NOT NULL,
  `locale` tinyint(3) NOT NULL,
  `description` text NOT NULL,
  `comment` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`page`, `locale`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `aowow_seo_descriptions` VALUES
    ('maps', 0, 'Maps of all zones with support for pins and coordinates display, with options for sharing.', null),
    ('maps', 2, 'Des cartes de toutes les zones avec le support des marqueurs et des coordonnées, plus des options pour partager le contenu.', null),
    ('maps', 3, 'Karten aller Gebiete. Unterstützt Markierungen und Koordinaten. Karten können weitergegeben werden.', null),
    ('maps', 4, '所有区域地图，支持标记和坐标显示，并提供分享选项。', 'automated translation'),
    ('maps', 6, 'Mapas de todas las zonas con soporte para marcadores y visualización de coordenadas, con opciones para compartir.', null),
    ('maps', 8, 'Карты всех локаций, с поддержкой маркеров и отображением координат, с возможностью поделиться.', null),

    ('search', 0, 'The largest World of Warcraft (WoW) information website, featuring information on classes, professions, raids, and more.', null),
    ('search', 2, 'Le plus grand site d''information sur World of Warcraft (WoW), proposant des informations sur les classes, professions, raids, et plus.', null),
    ('search', 3, 'Die größte World of Warcraft (WoW) Datenbank mit News, Guides, Talentrechner, Gegenständen, Quests, Profilen und noch viel mehr.', null),
    ('search', 4, '最大的魔兽世界（WoW）资讯网站，数据库、职业讲解、攻略、专业技能、团本、成就。', null),
    ('search', 6, 'La mayor web de información sobre World of Warcraft (WoW), con información sobre clases, profesiones, bandas y mucho más!', null),
    ('search', 8, 'Крупнейший сайт с информацией о World of Warcraft (WoW). Здесь вы найдете руководства и узнаете все подробности, касающиеся профессий, классов, рейдов и многом другом.', null),

    ('petcalc', 0, 'Hunter Pet Talent Calculator for World of Warcraft. Cunning, Tenacity and Ferocity.', null),
    ('petcalc', 2, 'Calculateur de talents de familiers pour Wrath of the Lich King. Ruse, Ténacité et Férocité.', null),
    ('petcalc', 3, 'Begleiterrechner für Wrath of the Lich King. List, Hartnäckigkeit und Wildheit.', null),
    ('petcalc', 4, '魔兽世界猎手宠物天赋模拟器。狡诈、坚韧、狂野。', null),
    ('petcalc', 6, 'Calculadora de talentos de Mascotas de Cazadores para World of Warcraft. Astucia, Tenacidad y Ferocidad.', null),
    ('petcalc', 8, 'Калькулятор талантов питомцев для World of Warcraft. Хитрость, Упорство, Свирепость.', null),

    ('talent', 0, 'Talent Calculator for Wrath of the Lich King. Theorycraft, plan, and share your WotLK character builds for all ten classes.', null),
    ('talent', 2, 'Calculateur de talents pour Wrath of the Lich King : préparez et partagez vos configurations de personnage pour les dix classes !', null),
    ('talent', 3, 'Talentrechner für Wrath of the Lich King Classic. Theorycraftet, plant und teilt eure Charakterbuilds für alle zehn Klassen.', null),
    ('talent', 4, '巫妖王之怒天赋模拟器。为所有十个职业进行理论构筑、规划并分享你的巫妖王之怒角色配置。', 'automated translation'),
    ('talent', 6, 'Calculadora de Talentos para Wrath of the Lich King. Planea, teoriza y comparte tus configuraciones de personaje para las 10 clases.', null),
    ('talent', 8, 'Калькулятор талантов Wrath of the Lich King. Создавайте и делитесь билдами классических персонажей всех десяти классов.', null),

    ('compare', 0, 'Add items or item sets to a table to compare stats, including support for stat weights.', null),
    ('compare', 2, 'Ajouter des objets ou des ensembles d''objets à une table pour comparer leurs statistiques, avec le support des balances de statistiques.', null),
    ('compare', 3, 'Füge Gegenstände oder Ausrüstungssets der Tabelle hinzu um ihre Werte zu gewichten und vergleichen.', null),
    ('compare', 4, '将物品或物品套装添加到表格中以比较属性，并支持属性权重。', 'automated translation'),
